import { _decorator, Camera, Component, easing, Node, Tween, tween, Vec3 } from 'cc';
import { BuildingType, CommonEvent, GameResult, MoveType } from '../Common/CommonEnum';
const { ccclass, property } = _decorator;

@ccclass('MainCamera')
export class MainCamera extends Component {
    @property({type: Node, displayName: '相机父节点'})
    private cameraParent: Node = null!;
    @property(Camera)
    private camera: Camera = null!;
    @property({ displayName: '平滑跟随时间' })
    private smoothTime: number = 0.1;

    private isShaking = false;
    private targetPosition: Vec3 | null = null;
    private currentVelocity: Vec3 = new Vec3();
    private isFollowing: boolean = false;
    private pauseFollowing: boolean = false;
    
    onLoad() {
        app.event.on(CommonEvent.HerMove, this.onHeroMove, this);
        app.event.on(CommonEvent.ShowOver, this.onShowOver, this);
        app.event.on(CommonEvent.ShakeCamera, this.onShakeCamera, this);
        app.event.on(CommonEvent.ShowOut, this.onShowOut, this);
    }

    onDestroy() {
        app.event.offAllByTarget(this);
    }

    private onShakeCamera(data: {intensity: number, duration: number, source: Node}) {
        if (this.isSourceInCameraView(data.source)) {
            this.shake(data?.intensity, data?.duration);
        }
    }

    /**
     * 判断震动源是否在摄像机可见范围内
     * @param source 震动源节点
     * @returns 是否在可见范围内
     */
    private isSourceInCameraView(source: Node): boolean {
        if (!source || !this.camera) return false;
        
        // 获取相机和震动源的世界坐标
        const cameraPos = this.camera.node.getWorldPosition();
        const sourcePos = source.getWorldPosition();
        
        // 计算距离
        const distance = Vec3.distance(cameraPos, sourcePos);
        
        // 设置可见距离范围（可以根据需要调整）
        const maxDistance = 1000;  // 最大震动距离
        
        if (distance > maxDistance) {
            return false;
        }
        
        // 使用相机的屏幕坐标转换来判断是否在视锥体内
        const screenPos = this.camera.worldToScreen(sourcePos);
        
        // 获取屏幕尺寸 - 使用更简单的固定值或相机的渲染范围
        const screenWidth = 720;  // 可以根据项目设置调整
        const screenHeight = 1280;  // 可以根据项目设置调整
        
        // 判断是否在屏幕范围内（包含一定的边界扩展）
        const margin = 200; // 边界扩展，允许稍微超出屏幕的物体也能触发震动
        return screenPos.x >= -margin && 
               screenPos.x <= screenWidth + margin && 
               screenPos.y >= -margin && 
               screenPos.y <= screenHeight + margin;
    }
    
    private onHeroMove(heroPos: Vec3) {
        if (manager.game.isGamePause || this.pauseFollowing) return;
        this.targetPosition = heroPos.add(new Vec3(0, 33, 25));
        this.isFollowing = true;
    }

    protected lateUpdate(dt: number): void {
        if (this.targetPosition && this.isFollowing) {
            const currentPos = this.cameraParent.getWorldPosition();
            const smoothedPos = new Vec3();
            
            // 使用插值实现平滑跟随
            const t = Math.min(dt / this.smoothTime, 1.0);
            Vec3.lerp(smoothedPos, currentPos, this.targetPosition, t);
            
            this.cameraParent.setWorldPosition(smoothedPos);
            app.event.emit(CommonEvent.CameraMove, smoothedPos);
            this.targetPosition = null;
        }
    }

    private onShowOver() {
        this.pauseFollowing = true;
        tween(this.node)
            .to(1.2, {
                position: new Vec3(2, 30, 12)
            },{easing: easing.quintOut})
            .start();
        tween(this.camera)
            .to(1.2, {
                fov: 40
            },{easing: easing.quintOut})
            .call(() => {
                // this.pauseFollowing = false;
            })
            .start();
    }

    private onShowOut(data: {cb: ()=>void}) {
        this.pauseFollowing = true;
        tween(this.node)
            .to(1.2, {
                // position: new Vec3(2, 30, 12),
                x: 2,
            },{easing: easing.quintOut})
            .delay(1.5)
            .to(0.5, {
                x: 0,
            },{easing: easing.quintOut})
            .call(() => {
                this.pauseFollowing = false;
                data.cb?.();
            })
            .start();
        tween(this.camera.node)
            .to(1.2, {
                eulerAngles: new Vec3(-43, 0, 0)
            },{easing: easing.quintOut})
            .delay(1.5)
            .to(0.5, {
                eulerAngles: new Vec3(-50, 0, 0)
            },{easing: easing.quintOut})
            .start();
    }

    /**
     * 屏幕震动效果
     * @param intensity 震动强度 (默认: 5)
     * @param duration 震动持续时间 (默认: 0.5秒)
     * @param frequency 震动频率 (默认: 20次/秒)
     */
    public shake(intensity: number = 5, duration: number = 0.08) {
        if (this.isShaking) {
            Tween.stopAllByTarget(this.camera.node);
            this.camera.node.setPosition(Vec3.ZERO);
        };
        this.isShaking = true;
        
        tween(this.camera.node)
            .to(duration/2, {
                position: new Vec3(0, intensity, 0)
            },{easing: easing.cubicOut})
            .to(duration/2, {
                position: new Vec3(0, 0, 0)
            },{easing: easing.cubicIn})
            .call(() => {
                this.isShaking = false;
            })
            .start();
    }

    /**
     * 停止震动
     */
    public stopShake() {
        this.isShaking = false;
        this.camera.node.setPosition(Vec3.ZERO);
    }
}


